module multi_16bit(
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output [31:0] yout,
    output done,
    input ain,
    input bin,
    output yout_r,
    input ain,
    input bin
);

// [STEP 1] Table 11-4: 16-bit multiplier: Declare local registers and wires to hold shift count, multiplicand, multiplier, and product values.
    reg [4:0] i; // shift count register
    reg [15:0] areg; // multiplicand register
    reg [15:0] breg; // multiplier register
    reg [31:0] p; // product register
// [STEP 2] Table 11-4: Reset the shift count register to 0 on the falling edge of the reset signal.
    always @(*) begin
        if (!rst_n) begin
            i = 0;
        end
    end
// [STEP 3] Table 11-4: Increment the shift count register by 1 on the positive edge of the clock signal if the start signal is 1 and the shift count register is less than 17; otherwise, reset the shift count register to 0.
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            i <= 0;
        end else if (start && i < 17) begin
            i <= i + 1;
        end else if (!start) begin
            i <= 0;
        end
    end
// [STEP 4] Table 11-4: Declare an always block that triggers on the positive edge of the clock signal or the falling edge of the reset signal.
// Table 11-4: Initialize the multiplicand register and multiplier register to 0 on the falling edge of the reset signal.
// Table 11-4: Shift and accumulate the product by adding the multiplicand register shifted by i-1 positions to the product register if the bit at position i-1 in the multiplier register is 1.
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            areg <= 16'b0;
            breg <= 16'b0;
            p <= 32'b0;
        end else if (start) begin
            if (i == 0) begin
                areg <= ain;
                breg <= bin;
            end else if (i < 17) begin
                if (breg[i-1]) begin
                    p <= p + {areg << (i-1), 1'b0};
                end
            end
        end
    end
// [STEP 5] Table 11-4: Assign the product register to the output.
    assign yout = p;
// [STEP 6] Table 11-4: To be able to observe the done signal in simulation, assign the done_r value to the done signal.
    reg done_r;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            done_r <= 0;
        end else if (i == 16) begin
            done_r <= 1;
        end else if (i == 17) begin
            done_r <= 0;
        end
    end
    assign done = done_r;
endmodule
